mapper.select:
SELECT DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m') AS month, COALESCE(SUM(CASE WHEN c.sign_date >= DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m-01') AND c.sign_date <= LAST_DAY(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH)) THEN 1 ELSE 0 END), 0) AS dealCount FROM ( SELECT 5 AS n UNION ALL SELECT 4 UNION ALL SELECT 3 UNION ALL SELECT 2 UNION ALL SELECT 1 UNION ALL SELECT 0 ) seq LEFT JOIN biz_contract c ON c.del_flag = '0'
AND c.park_id = #{parkId}
GROUP BY seq.n ORDER BY seq.n DESC

SELECT p.payment_id AS id, c.customer_name AS tenantName, COALESCE(p.amount_due, 0) - COALESCE(p.amount_paid, 0) AS amount, p.pay_deadline AS dueDate, COALESCE(n.miniapp_status, n.sms_status, n.inbox_status, 'pending') AS noticeStatus FROM biz_contract_payment p LEFT JOIN biz_contract c ON c.contract_id = p.contract_id LEFT JOIN biz_payment_notice n ON n.payment_id = p.payment_id AND n.del_flag = '0' WHERE COALESCE(p.direction, 'receivable') = 'receivable' AND COALESCE(p.pay_status, '0') != '1' AND NOT EXISTS ( SELECT 1 FROM biz_payment_notice sent_notice WHERE sent_notice.payment_id = p.payment_id AND sent_notice.del_flag = '0' AND ( sent_notice.sms_status = 'success' OR sent_notice.email_status = 'success' OR sent_notice.inbox_status = 'success' OR sent_notice.miniapp_status = 'success' ) )
AND p.park_id = #{parkId}
ORDER BY p.pay_deadline ASC, p.payment_id DESC LIMIT 8
